import { useEffect, useRef } from 'react';
import styles from './Gallery.module.css';
import gallery1 from '../assets/gallery-1.png';
import gallery2 from '../assets/gallery-2.png';
import gallery3 from '../assets/gallery-3.png';

interface GalleryItem {
  src: string;
  alt: string;
  label: string;
}

const baseItems: GalleryItem[] = [
  {
    src: gallery1,
    alt: 'Chopsticks lifting noodles from a bowl of ramen with soft egg and corn',
    label: 'Tonkotsu',
  },
  {
    src: gallery3,
    alt: 'A rich white broth ramen bowl with soft egg and scallion',
    label: 'Paitan Bowl',
  },
  {
    src: gallery2,
    alt: 'A vegetable forward ramen bowl with bok choy, corn and soft egg',
    label: 'Vegetable Shio',
  },
  {
    src: gallery3,
    alt: 'A dark broth ramen bowl topped with seaweed, greens and soft egg',
    label: 'Miso Ramen',
  },
];

// Three copies back-to-back so the middle set always has a full set on
// either side. We only ever render this; we never let the browser scroll
// it natively, so there is no edge to get stuck at.
const loopedItems: GalleryItem[] = [...baseItems, ...baseItems, ...baseItems];

function Gallery(): JSX.Element {
  const viewportRef = useRef<HTMLDivElement>(null);
  const trackRef = useRef<HTMLDivElement>(null);
  const setWidthRef = useRef(0);
  const offsetRef = useRef(0);
  const touchStartXRef = useRef<number | null>(null);

  const applyOffset = () => {
    const setWidth = setWidthRef.current;
    const track = trackRef.current;
    if (!setWidth || !track) return;

    // Wrap into [0, setWidth) so the offset can never run away in
    // either direction, no matter how far or how fast you scroll.
    let wrapped = offsetRef.current % setWidth;
    if (wrapped < 0) wrapped += setWidth;
    offsetRef.current = wrapped;

    // Always render from the middle copy, shifted by the wrapped offset.
    track.style.transform = `translateX(-${setWidth + wrapped}px)`;
  };

  useEffect(() => {
    const track = trackRef.current;
    if (!track) return;

    const measure = () => {
      setWidthRef.current = track.scrollWidth / 3;
      applyOffset();
    };

    measure();
    window.addEventListener('resize', measure);
    return () => window.removeEventListener('resize', measure);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    const viewport = viewportRef.current;
    if (!viewport) return;

    const handleWheel = (event: WheelEvent) => {
      const delta =
        Math.abs(event.deltaY) > Math.abs(event.deltaX)
          ? event.deltaY
          : event.deltaX;
      if (delta === 0) return;
      event.preventDefault();
      offsetRef.current += delta;
      applyOffset();
    };

    const handleTouchStart = (event: TouchEvent) => {
      touchStartXRef.current = event.touches[0].clientX;
    };

    const handleTouchMove = (event: TouchEvent) => {
      if (touchStartXRef.current === null) return;
      const currentX = event.touches[0].clientX;
      const delta = touchStartXRef.current - currentX;
      touchStartXRef.current = currentX;
      offsetRef.current += delta;
      applyOffset();
    };

    const handleTouchEnd = () => {
      touchStartXRef.current = null;
    };

    viewport.addEventListener('wheel', handleWheel, { passive: false });
    viewport.addEventListener('touchstart', handleTouchStart, {
      passive: true,
    });
    viewport.addEventListener('touchmove', handleTouchMove, {
      passive: true,
    });
    viewport.addEventListener('touchend', handleTouchEnd);

    return () => {
      viewport.removeEventListener('wheel', handleWheel);
      viewport.removeEventListener('touchstart', handleTouchStart);
      viewport.removeEventListener('touchmove', handleTouchMove);
      viewport.removeEventListener('touchend', handleTouchEnd);
    };
  }, []);

  return (
    <section className={styles.gallery}>
      <div className={styles.viewport} ref={viewportRef}>
        <div className={styles.track} ref={trackRef}>
          {loopedItems.map((item, index) => (
            <div className={styles.item} key={`${item.label}-${index}`}>
              <div className={styles.imageWrap}>
                <img src={item.src} alt={item.alt} draggable={false} />
              </div>
              <span className={styles.label}>{item.label}</span>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Gallery;
